// 学习进度管理
const STORAGE_KEY = 'english_app_progress';
const FAVORITES_KEY = 'english_app_favorites';
const CUSTOM_WORDS_KEY = 'english_app_custom';

function getProgress() {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : {};
  } catch(e) { return {}; }
}

function saveProgress(wordId, correct) {
  const progress = getProgress();
  if (!progress[wordId]) {
    progress[wordId] = { attempts: 0, correct: 0, lastReviewed: null };
  }
  progress[wordId].attempts++;
  if (correct) progress[wordId].correct++;
  progress[wordId].lastReviewed = Date.now();
  localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
}

function getFavorites() {
  try {
    const data = localStorage.getItem(FAVORITES_KEY);
    return data ? JSON.parse(data) : [];
  } catch(e) { return []; }
}

function toggleFavorite(wordId) {
  const favorites = getFavorites();
  const idx = favorites.indexOf(wordId);
  if (idx > -1) favorites.splice(idx, 1);
  else favorites.push(wordId);
  localStorage.setItem(FAVORITES_KEY, JSON.stringify(favorites));
  return favorites;
}

function getCustomWords() {
  try {
    const data = localStorage.getItem(CUSTOM_WORDS_KEY);
    return data ? JSON.parse(data) : [];
  } catch(e) { return []; }
}

function addCustomWord(word) {
  const words = getCustomWords();
  word.id = 'custom_' + Date.now();
  words.push(word);
  localStorage.setItem(CUSTOM_WORDS_KEY, JSON.stringify(words));
  return words;
}

function removeCustomWord(id) {
  let words = getCustomWords();
  words = words.filter(w => w.id !== id);
  localStorage.setItem(CUSTOM_WORDS_KEY, JSON.stringify(words));
  return words;
}

// 获取所有可用的词汇（内置 + 自定义）
function getAllWords() {
  const custom = getCustomWords();
  const builtin = VOCABULARY.map((w, i) => ({ ...w, id: 'builtin_' + i }));
  return [...builtin, ...custom
  ];
}
